diff --git a/mux.go b/mux.go
index eaff897..f76aa70 100644
--- a/mux.go
+++ b/mux.go
@@ -409,7 +409,11 @@ type WalkFunc func(route *Route, router *Router, ancestors []*Route) error

 func (r *Router) walk(walkFn WalkFunc, ancestors []*Route) error {
 	for _, t := range r.routes {
-		err := walkFn(t, r, ancestors)
+		// Pass a copy of ancestors so the WalkFunc cannot observe mutations
+		// made by subsequent iterations or recursive descents.
+		ancestorsCopy := make([]*Route, len(ancestors))
+		copy(ancestorsCopy, ancestors)
+		err := walkFn(t, r, ancestorsCopy)
 		if err == SkipRouter {
 			continue
 		}
@@ -418,21 +422,17 @@ func (r *Router) walk(walkFn WalkFunc, ancestors []*Route) error {
 		}
 		for _, sr := range t.matchers {
 			if h, ok := sr.(*Router); ok {
-				ancestors = append(ancestors, t)
-				err := h.walk(walkFn, ancestors)
+				err := h.walk(walkFn, append(append([]*Route{}, ancestors...), t))
 				if err != nil {
 					return err
 				}
-				ancestors = ancestors[:len(ancestors)-1]
 			}
 		}
 		if h, ok := t.handler.(*Router); ok {
-			ancestors = append(ancestors, t)
-			err := h.walk(walkFn, ancestors)
+			err := h.walk(walkFn, append(append([]*Route{}, ancestors...), t))
 			if err != nil {
 				return err
 			}
-			ancestors = ancestors[:len(ancestors)-1]
 		}
 	}
 	return nil
